   228→func TestHandleLifecycleTurnEnd_EmptyRepository(t *testing.T) {
   229→	// Cannot use t.Parallel() because we use t.Chdir()
   230→	tmpDir := t.TempDir()
   231→	t.Chdir(tmpDir)
   232→
   233→	// Initialize an empty git repo (no commits)
   234→	if err := os.MkdirAll(".git/objects", 0o755); err != nil {
   235→		t.Fatalf("Failed to create .git: %v", err)
   236→	}
   237→	if err := os.WriteFile(".git/HEAD", []byte("ref: refs/heads/main\n"), 0o644); err != nil {
   238→		t.Fatalf("Failed to create HEAD: %v", err)
   239→	}
   240→	paths.ClearRepoRootCache()
   241→
   242→	// Create a transcript file
   243→	transcriptPath := filepath.Join(tmpDir, "transcript.jsonl")
   244→	if err := os.WriteFile(transcriptPath, []byte(`{"type":"user","message":"test"}`+"\n"), 0o644); err != nil {
   245→		t.Fatalf("Failed to create transcript: %v", err)
   246→	}
   247→
   248→	ag := newMockAgent()
   249→	event := &agent.Event{
   250→		Type:       agent.TurnEnd,
   251→		SessionID:  "test-session",
   252→		SessionRef: transcriptPath,
   253→	}
   254→
   255→	err := handleLifecycleTurnEnd(ag, event)
   256→
   257→	// Should return a SilentError wrapping ErrEmptyRepository
   258→	if err == nil {
   259→		t.Error("expected error for empty repository, got nil")
   260→	}
   261→
   262→	var silentErr *SilentError
   263→	if !errors.As(err, &silentErr) {
   264→		t.Errorf("expected SilentError, got: %T", err)
   265→	}
   266→	if !errors.Is(silentErr.Unwrap(), strategy.ErrEmptyRepository) {
   267→		t.Errorf("expected ErrEmptyRepository, got: %v", silentErr.Unwrap())
   268→	}
   269→}
