   390→func TestCreateContextFile_Format(t *testing.T) {
   391→	t.Parallel()
   392→
   393→	tmpDir := t.TempDir()
   394→	contextFile := filepath.Join(tmpDir, "context.md")
   395→
   396→	prompts := []string{"What is the meaning of life?", "Follow-up question here"}
   397→	summary := "This session explored philosophical questions."
   398→
   399→	err := createContextFile(contextFile, "feat: add philosophy", "session-123", prompts, summary)
   400→	if err != nil {
