   403→
   404→	content, err := os.ReadFile(contextFile)
   405→	if err != nil {
   406→		t.Fatalf("failed to read context file: %v", err)
   407→	}
   408→
   409→	contentStr := string(content)
   410→
   411→	// Check for expected sections
   412→	if !strings.Contains(contentStr, "# Session Context") {
