   421→	if !strings.Contains(contentStr, "## Prompts") {
   422→		t.Error("expected '## Prompts' section")
   423→	}
   424→	if !strings.Contains(contentStr, "### Prompt 1") {
   425→		t.Error("expected '### Prompt 1' subsection")
