   433→	if !strings.Contains(contentStr, "## Summary") {
   434→		t.Error("expected '## Summary' section")
   435→	}
   436→	if !strings.Contains(contentStr, "philosophical questions") {
   437→		t.Error("expected summary content")
   438→	}
   439→}
