   473→// --- Event type routing tests ---
   474→
   475→func TestDispatchLifecycleEvent_RoutesToCorrectHandler(t *testing.T) {
   476→	t.Parallel()
   477→
   478→	// Test that each event type is routed (we can't easily verify which handler
   479→	// was called without dependency injection, but we can verify no panic and
   480→	// expected error types for each event type with minimal required data)
   481→
   482→	testCases := []struct {
   483→		name        string
   484→		eventType   agent.EventType
   485→		sessionID   string
   486→		expectError bool
   487→		errorSubstr string
   488→	}{
   489→		{
   490→			name:        "SessionStart with empty session ID",
   491→			eventType:   agent.SessionStart,
   492→			sessionID:   "",
   493→			expectError: true,
   494→			errorSubstr: "no session_id",
   495→		},
   496→		{
   497→			name:        "TurnStart with empty session ID",
   498→			eventType:   agent.TurnStart,
   499→			sessionID:   "",
   500→			expectError: true,
   501→			errorSubstr: "no session_id",
   502→		},
   503→		{
   504→			name:        "TurnEnd with empty transcript",
   505→			eventType:   agent.TurnEnd,
   506→			sessionID:   "test",
   507→			expectError: true,
   508→			errorSubstr: "transcript file not found",
   509→		},
   510→		{
   511→			name:        "Compaction with empty transcript is no-op",
   512→			eventType:   agent.Compaction,
   513→			sessionID:   "test",
   514→			expectError: false, // Compaction just resets offset; doesn't read transcript
   515→		},
   516→		{
   517→			name:        "SessionEnd with empty session ID is no-op",
   518→			eventType:   agent.SessionEnd,
   519→			sessionID:   "",
   520→			expectError: false,
   521→		},
   522→		{
   523→			name:        "SubagentStart with valid data",
   524→			eventType:   agent.SubagentStart,
   525→			sessionID:   "test",
   526→			expectError: true, // Will fail due to CapturePreTaskState needing git repo
   527→			errorSubstr: "failed to capture pre-task state",
   528→		},
   529→		{
   530→			name:        "SubagentEnd with valid data",
   531→			eventType:   agent.SubagentEnd,
   532→			sessionID:   "test",
   533→			expectError: false, // Succeeds when run from a valid git repo
   534→		},
   535→	}
   536→
   537→	for _, tc := range testCases {
   538→		t.Run(tc.name, func(t *testing.T) {
   539→			t.Parallel()
   540→
   541→			ag := newMockAgent()
   542→			event := &agent.Event{
   543→				Type:      tc.eventType,
   544→				SessionID: tc.sessionID,
   545→				Timestamp: time.Now(),
   546→			}
   547→
   548→			err := DispatchLifecycleEvent(ag, event)
   549→
   550→			if tc.expectError {
   551→				if err == nil {
   552→					t.Errorf("expected error containing %q, got nil", tc.errorSubstr)
   553→				} else if !strings.Contains(err.Error(), tc.errorSubstr) {
   554→					t.Errorf("expected error containing %q, got: %v", tc.errorSubstr, err)
   555→				}
   556→			} else {
   557→				if err != nil {
   558→					t.Errorf("expected no error, got: %v", err)
   559→				}
   560→			}
   561→		})
   562→	}
   563→}
