   567→// setupGitRepoWithCommit initializes a git repo with an initial commit.
   568→func setupGitRepoWithCommit(t *testing.T, dir string) {
   569→	t.Helper()
   570→
   571→	// Initialize git repo
   572→	if err := os.MkdirAll(filepath.Join(dir, ".git", "objects"), 0o755); err != nil {
   573→		t.Fatalf("Failed to create .git/objects: %v", err)
   574→	}
   575→	if err := os.MkdirAll(filepath.Join(dir, ".git", "refs", "heads"), 0o755); err != nil {
   576→		t.Fatalf("Failed to create .git/refs/heads: %v", err)
   577→	}
   578→	if err := os.WriteFile(filepath.Join(dir, ".git", "HEAD"), []byte("ref: refs/heads/main\n"), 0o644); err != nil {
   579→		t.Fatalf("Failed to create HEAD: %v", err)
   580→	}
   581→
   582→	// Create a dummy file to commit
   583→	if err := os.WriteFile(filepath.Join(dir, "README.md"), []byte("# Test\n"), 0o644); err != nil {
   584→		t.Fatalf("Failed to create README.md: %v", err)
   585→	}
   586→
   587→	// Use go-git to create an initial commit
