   127→
   128→// Transition computes the next phase and required actions given the current
   129→// phase and an event. This is a pure function with no side effects.
   130→//
   131→// Empty or unknown phase values are normalized to PhaseIdle for backward
   132→// compatibility with session state files created before phase tracking.
   133→func Transition(current Phase, event Event, ctx TransitionContext) TransitionResult {
   134→	// Normalize empty/unknown phase to idle for backward compatibility.
   135→	current = PhaseFromString(string(current))
   136→
   137→	switch current {
   138→	case PhaseIdle:
   139→		return transitionFromIdle(event, ctx)
   140→	case PhaseActive:
   141→		return transitionFromActive(event, ctx)
   142→	case PhaseEnded:
   143→		return transitionFromEnded(event, ctx)
   144→	default:
   145→		// PhaseFromString guarantees we only get known phases, but the
   146→		// exhaustive linter requires handling the default case.
   147→		return TransitionResult{NewPhase: PhaseIdle}
   148→	}
   149→}
   150→
   151→func transitionFromIdle(event Event, ctx TransitionContext) TransitionResult {
   152→	switch event {
   153→	case EventTurnStart:
   154→		return TransitionResult{
   155→			NewPhase: PhaseActive,
   156→			Actions:  []Action{ActionUpdateLastInteraction},
   157→		}
   158→	case EventTurnEnd:
   159→		// Turn end while idle is a no-op (no active turn to end).
   160→		return TransitionResult{NewPhase: PhaseIdle}
   161→	case EventGitCommit:
   162→		if ctx.IsRebaseInProgress {
   163→			return TransitionResult{NewPhase: PhaseIdle}
   164→		}
   165→		return TransitionResult{
   166→			NewPhase: PhaseIdle,
   167→			Actions:  []Action{ActionCondense, ActionUpdateLastInteraction},
   168→		}
   169→	case EventSessionStart:
   170→		// Already condensable, no-op.
   171→		return TransitionResult{NewPhase: PhaseIdle}
   172→	case EventSessionStop:
   173→		return TransitionResult{
   174→			NewPhase: PhaseEnded,
   175→			Actions:  []Action{ActionUpdateLastInteraction},
   176→		}
   177→	case EventCompaction:
   178→		// Compaction while idle shouldn't happen, but condense if there's work.
   179→		return TransitionResult{
   180→			NewPhase: PhaseIdle,
   181→			Actions:  []Action{ActionCondenseIfFilesTouched, ActionUpdateLastInteraction},
   182→		}
   183→	default:
   184→		return TransitionResult{NewPhase: PhaseIdle}
   185→	}
   186→}
   187→
   188→func transitionFromActive(event Event, ctx TransitionContext) TransitionResult {
   189→	switch event {
   190→	case EventTurnStart:
   191→		// Ctrl-C recovery: agent crashed or user interrupted mid-turn.
   192→		return TransitionResult{
   193→			NewPhase: PhaseActive,
   194→			Actions:  []Action{ActionUpdateLastInteraction},
   195→		}
   196→	case EventTurnEnd:
   197→		return TransitionResult{
   198→			NewPhase: PhaseIdle,
   199→			Actions:  []Action{ActionUpdateLastInteraction},
   200→		}
   201→	case EventGitCommit:
   202→		if ctx.IsRebaseInProgress {
   203→			return TransitionResult{NewPhase: PhaseActive}
   204→		}
   205→		return TransitionResult{
   206→			NewPhase: PhaseActive,
   207→			Actions:  []Action{ActionCondense, ActionUpdateLastInteraction},
   208→		}
   209→	case EventSessionStart:
   210→		return TransitionResult{
   211→			NewPhase: PhaseActive,
   212→			Actions:  []Action{ActionWarnStaleSession},
   213→		}
   214→	case EventSessionStop:
   215→		return TransitionResult{
   216→			NewPhase: PhaseEnded,
   217→			Actions:  []Action{ActionUpdateLastInteraction},
   218→		}
   219→	case EventCompaction:
   220→		// Compaction mid-turn: save current progress but stay active.
   221→		// The transcript offset will be reset by the compaction handler.
   222→		return TransitionResult{
   223→			NewPhase: PhaseActive,
   224→			Actions:  []Action{ActionCondenseIfFilesTouched, ActionUpdateLastInteraction},
   225→		}
   226→	default:
   227→		return TransitionResult{NewPhase: PhaseActive}
   228→	}
   229→}
   230→
   231→func transitionFromEnded(event Event, ctx TransitionContext) TransitionResult {
   232→	switch event {
   233→	case EventTurnStart:
   234→		return TransitionResult{
   235→			NewPhase: PhaseActive,
   236→			Actions:  []Action{ActionClearEndedAt, ActionUpdateLastInteraction},
   237→		}
   238→	case EventTurnEnd:
   239→		// Turn end while ended is a no-op.
   240→		return TransitionResult{NewPhase: PhaseEnded}
   241→	case EventGitCommit:
   242→		if ctx.IsRebaseInProgress {
   243→			return TransitionResult{NewPhase: PhaseEnded}
   244→		}
   245→		if ctx.HasFilesTouched {
   246→			return TransitionResult{
   247→				NewPhase: PhaseEnded,
   248→				Actions:  []Action{ActionCondenseIfFilesTouched, ActionUpdateLastInteraction},
   249→			}
   250→		}
   251→		return TransitionResult{
   252→			NewPhase: PhaseEnded,
   253→			Actions:  []Action{ActionDiscardIfNoFiles, ActionUpdateLastInteraction},
   254→		}
   255→	case EventSessionStart:
   256→		return TransitionResult{
   257→			NewPhase: PhaseIdle,
   258→			Actions:  []Action{ActionClearEndedAt},
   259→		}
   260→	case EventSessionStop:
   261→		// Already ended, no-op.
   262→		return TransitionResult{NewPhase: PhaseEnded}
   263→	case EventCompaction:
   264→		// Compaction while ended shouldn't happen, no-op.
   265→		return TransitionResult{NewPhase: PhaseEnded}
   266→	default:
   267→		return TransitionResult{NewPhase: PhaseEnded}
   268→	}
   269→}
