   271→// ActionHandler defines strategy-specific side effects for state transitions.
   272→// The compiler enforces that every strategy-specific action has a handler.
   273→type ActionHandler interface {
   274→	HandleCondense(state *State) error
   275→	HandleCondenseIfFilesTouched(state *State) error
   276→	HandleDiscardIfNoFiles(state *State) error
   277→	HandleWarnStaleSession(state *State) error
   278→}
   279→
   280→// NoOpActionHandler is a default ActionHandler where all methods are no-ops.
   281→// Embed this in handler structs to only override the methods you need.
   282→type NoOpActionHandler struct{}
   283→
   284→func (NoOpActionHandler) HandleCondense(_ *State) error               { return nil }
   285→func (NoOpActionHandler) HandleCondenseIfFilesTouched(_ *State) error { return nil }
   286→func (NoOpActionHandler) HandleDiscardIfNoFiles(_ *State) error       { return nil }
   287→func (NoOpActionHandler) HandleWarnStaleSession(_ *State) error       { return nil }
   288→
   289→// ApplyTransition applies a TransitionResult to state: sets the new phase
   290→// unconditionally, then executes all actions. Common actions
   291→// (UpdateLastInteraction, ClearEndedAt) always run regardless of handler
   292→// errors so that bookkeeping fields stay consistent with the new phase.
   293→// Strategy-specific handler actions stop on the first error; subsequent
   294→// handler actions are skipped but common actions continue. Returns the
   295→// first handler error, or nil.
   296→func ApplyTransition(state *State, result TransitionResult, handler ActionHandler) error {
   297→	state.Phase = result.NewPhase
   298→
   299→	var handlerErr error
   300→	for _, action := range result.Actions {
   301→		switch action {
   302→		// Common actions: always applied, even after a handler error.
   303→		case ActionUpdateLastInteraction:
   304→			now := time.Now()
   305→			state.LastInteractionTime = &now
   306→		case ActionClearEndedAt:
   307→			state.EndedAt = nil
   308→
   309→		// Strategy-specific actions: skip remaining after the first handler error.
   310→		case ActionCondense:
   311→			if handlerErr == nil {
   312→				if err := handler.HandleCondense(state); err != nil {
   313→					handlerErr = fmt.Errorf("%s: %w", action, err)
   314→				}
   315→			}
   316→		case ActionCondenseIfFilesTouched:
   317→			if handlerErr == nil {
   318→				if err := handler.HandleCondenseIfFilesTouched(state); err != nil {
   319→					handlerErr = fmt.Errorf("%s: %w", action, err)
   320→				}
   321→			}
   322→		case ActionDiscardIfNoFiles:
   323→			if handlerErr == nil {
   324→				if err := handler.HandleDiscardIfNoFiles(state); err != nil {
   325→					handlerErr = fmt.Errorf("%s: %w", action, err)
   326→				}
   327→			}
   328→		case ActionWarnStaleSession:
   329→			if handlerErr == nil {
   330→				if err := handler.HandleWarnStaleSession(state); err != nil {
   331→					handlerErr = fmt.Errorf("%s: %w", action, err)
   332→				}
   333→			}
   334→		default:
   335→			if handlerErr == nil {
   336→				handlerErr = fmt.Errorf("unhandled action: %s", action)
   337→			}
   338→		}
   339→	}
   340→	return handlerErr
   341→}
