   343→// MermaidDiagram generates a Mermaid state diagram from the transition table.
   344→// The diagram is derived by calling Transition() for representative context
   345→// variants per phase/event, so it stays in sync with the implementation.
   346→func MermaidDiagram() string {
   347→	var b strings.Builder
   348→	b.WriteString("stateDiagram-v2\n")
   349→
   350→	// State declarations with descriptions.
   351→	b.WriteString("    state \"IDLE\" as idle\n")
   352→	b.WriteString("    state \"ACTIVE\" as active\n")
   353→	b.WriteString("    state \"ENDED\" as ended\n")
   354→	b.WriteString("\n")
   355→
   356→	// Context variants for GitCommit: rebase, files/no-files.
   357→	type contextVariant struct {
   358→		label string
   359→		ctx   TransitionContext
   360→	}
   361→
   362→	// For each phase/event, generate edges.
   363→	for _, phase := range allPhases {
   364→		for _, event := range allEvents {
   365→			var variants []contextVariant
   366→			switch {
   367→			case event == EventGitCommit && phase == PhaseEnded:
   368→				// HasFilesTouched only affects PhaseEnded transitions;
   369→				// other phases produce identical edges for both values.
   370→				variants = []contextVariant{
   371→					{"[files]", TransitionContext{HasFilesTouched: true}},
   372→					{"[no files]", TransitionContext{HasFilesTouched: false}},
   373→					{"[rebase]", TransitionContext{IsRebaseInProgress: true}},
   374→				}
   375→			case event == EventGitCommit:
   376→				variants = []contextVariant{
   377→					{"", TransitionContext{}},
   378→					{"[rebase]", TransitionContext{IsRebaseInProgress: true}},
   379→				}
   380→			default:
   381→				variants = []contextVariant{
   382→					{"", TransitionContext{}},
   383→				}
   384→			}
   385→
   386→			for _, v := range variants {
   387→				result := Transition(phase, event, v.ctx)
   388→
   389→				// Build edge label.
   390→				label := event.String()
   391→				if v.label != "" {
   392→					label += " " + v.label
   393→				}
   394→				if len(result.Actions) > 0 {
   395→					actionNames := make([]string, 0, len(result.Actions))
   396→					for _, a := range result.Actions {
   397→						actionNames = append(actionNames, a.String())
   398→					}
   399→					label += " / " + strings.Join(actionNames, ", ")
   400→				}
   401→
   402→				from := string(phase)
   403→				to := string(result.NewPhase)
   404→
   405→				fmt.Fprintf(&b, "    %s --> %s : %s\n", from, to, label)
   406→			}
   407→		}
   408→	}
   409→
   410→	return b.String()
   411→}
