    91→	inputJSON, _ := json.Marshal(hookInput) //nolint:errcheck,errchkjson // Test code; JSON marshal of simple map never fails
    92→
    93→	// Create the command with logging - use session-start hook which is a pass-through
    94→	cmd := newAgentHookVerbCmdWithLogging(agent.AgentNameClaudeCode, claudecode.HookNameSessionStart)
    95→
    96→	// Set stdin
