    98→	cmd.SetOut(&bytes.Buffer{})
    99→	cmd.SetErr(&bytes.Buffer{})
   100→
   101→	// Execute the command
   102→	err := cmd.Execute()
   103→	if err != nil {
   104→		t.Fatalf("command execution failed: %v", err)
   105→	}
   106→
   107→	// Close logging to flush
   108→	cleanup()
   109→
   110→	// Verify log file was created and contains expected content
   111→	logFile := filepath.Join(logsDir, "entire.log")
   112→	content, err := os.ReadFile(logFile)
   113→	if err != nil {
   114→		t.Fatalf("failed to read log file: %v", err)
   115→	}
   116→
   117→	logContent := string(content)
   118→	t.Logf("log content: %s", logContent)
   119→
   120→	// Parse each log line as JSON
   121→	lines := strings.Split(strings.TrimSpace(logContent), "\n")
   122→	if len(lines) == 0 {
   123→		t.Fatal("expected at least one log line")
