   147→			}
   148→			if strings.Contains(msg, "completed") {
   149→				foundCompletion = true
   150→				// Verify duration_ms is present
   151→				if _, ok := entry["duration_ms"]; !ok {
   152→					t.Error("expected duration_ms in completion log")
   153→				}
   154→				// Verify success status
   155→				if entry["success"] != true {
   156→					t.Errorf("expected success=true, got %v", entry["success"])
   157→				}
   158→			}
   159→		}
   160→	}
   161→
   162→	if !foundInvocation {
   163→		t.Error("expected to find hook invocation log")
   164→	}
   165→	if !foundCompletion {
   166→		t.Error("expected to find hook completion log")
   167→	}
   168→}
